    @staticmethod
    def get_master_key():
        return Fernet(MASTER_KEY)

class EncryptionManager:
    @staticmethod
    def encrypt(data):
        master_key = MasterKeyManager.get_master_key()
        f = Fernet(master_key)
        return f.encrypt(data)

    @staticmethod
    def decrypt(encrypted_data):
        master_key = MasterKeyManager.get_master_key()
        f = Fernet(master_key)
        return f.decrypt(encrypted_data)

class DecryptionManager:
    @staticmethod
    def decrypt(encrypted_data):
        master_key = MasterKeyManager.get_master_key()
        f = Fernet(master_key)
        return f.decrypt(encrypted_data)
